import os

# ---------------------------------------------------------------------------
# MQTT broker
# ---------------------------------------------------------------------------

BROKER_HOST = os.environ.get("MQTT_BROKER_HOST", "localhost")
BROKER_PORT = int(os.environ.get("MQTT_BROKER_PORT", "8883"))

CA_CERT = os.environ.get("MQTT_CA_CERT", "docker/mosquitto/certs/ca.crt")
