CLIENT_ID = "crowd-simulator"

# ---------------------------------------------------------------------------
# Timing
# ---------------------------------------------------------------------------

PUBLISH_INTERVAL_MIN = 15.0   # seconds – lower bound per stop
PUBLISH_INTERVAL_MAX = 20.0   # seconds – upper bound per stop
BACKFILL_STAGGER = 0.05       # seconds between initial publishes
STATS_LOG_INTERVAL = 30.0     # seconds between summary logs

# ---------------------------------------------------------------------------
# Simulation tuning
# ---------------------------------------------------------------------------

SIM_TIME_SCALE = float(os.environ.get("SIM_TIME_SCALE", "1.0"))
SIM_RANDOM_SEED: int | None = (
    int(os.environ.get("SIM_RANDOM_SEED"))
    if os.environ.get("SIM_RANDOM_SEED")
    else None
)

BASE_CAP_MIN = 3    # minimum peak-hour capacity for any bus stop
BASE_CAP_MAX = 15   # maximum peak-hour capacity for any bus stop

BIAS_STRENGTH = 0.3          # pull-toward-target coefficient
MAX_DELTA_STDDEV = 2.0       # Gaussian noise σ for the random walk

DIP_DROP_MIN = 0.40   # minimum fraction of count removed by a vehicle dip
DIP_DROP_MAX = 0.70   # maximum fraction removed

